
'use client';

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { MoreHorizontal, UserPlus } from "lucide-react";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuLabel, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";

const initialDrivers = [
  { id: 'D001', name: 'John Doe', avatar: 'https://placehold.co/40x40.png', route: 'North Route', status: 'Active', since: '2021-08-15' },
  { id: 'D002', name: 'Jane Smith', avatar: 'https://placehold.co/40x40.png', route: 'South Route', status: 'Active', since: '2020-03-10' },
  { id: 'D003', name: 'Peter Jones', avatar: 'https://placehold.co/40x40.png', route: 'East County', status: 'On Leave', since: '2019-11-20' },
  { id: 'D004', name: 'Mary Poppins', avatar: 'https://placehold.co/40x40.png', route: 'Westside', status: 'Active', since: '2022-01-30' },
  { id: 'D005', name: 'Mike Ross', avatar: 'https://placehold.co/40x40.png', route: 'N/A', status: 'Inactive', since: '2023-05-01' },
];

export default function DriverManagementPage() {
  const [drivers, setDrivers] = useState(initialDrivers);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const { toast } = useToast();

  const handleAddDriver = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const formData = new FormData(event.currentTarget);
    const newDriver = {
      id: `D00${drivers.length + 1}`,
      name: formData.get('name') as string,
      avatar: 'https://placehold.co/40x40.png',
      route: 'N/A',
      status: 'Active',
      since: new Date().toISOString().split('T')[0],
    };
    setDrivers(prev => [...prev, newDriver]);
    setIsDialogOpen(false);
    toast({
        title: "Driver Added",
        description: `${newDriver.name} has been successfully added to the roster.`,
    })
  };

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold font-headline">Driver Management</h1>
          <p className="text-muted-foreground">View, add, and manage your bus drivers.</p>
        </div>
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogTrigger asChild>
            <Button>
              <UserPlus className="mr-2 h-4 w-4" /> Add New Driver
            </Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Add New Driver</DialogTitle>
              <DialogDescription>Enter the details for the new driver.</DialogDescription>
            </DialogHeader>
            <form onSubmit={handleAddDriver}>
                <div className="grid gap-4 py-4">
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="name" className="text-right">Name</Label>
                        <Input id="name" name="name" className="col-span-3" required />
                    </div>
                    <div className="grid grid-cols-4 items-center gap-4">
                        <Label htmlFor="license" className="text-right">License No.</Label>
                        <Input id="license" name="license" className="col-span-3" required />
                    </div>
                </div>
                <DialogFooter>
                    <Button type="submit">Add Driver</Button>
                </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Driver Roster</CardTitle>
          <CardDescription>A list of all drivers in the system.</CardDescription>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Driver</TableHead>
                <TableHead>Assigned Route</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Member Since</TableHead>
                <TableHead><span className="sr-only">Actions</span></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {drivers.map((driver) => (
                <TableRow key={driver.id}>
                  <TableCell className="font-medium">
                    <div className="flex items-center gap-3">
                      <Avatar>
                        <AvatarImage src={driver.avatar} alt={driver.name} data-ai-hint="person avatar" />
                        <AvatarFallback>{driver.name.split(' ').map(n => n[0]).join('')}</AvatarFallback>
                      </Avatar>
                      <span>{driver.name}</span>
                    </div>
                  </TableCell>
                  <TableCell>{driver.route}</TableCell>
                  <TableCell>
                    <Badge variant={driver.status === 'Active' ? 'default' : driver.status === 'On Leave' ? 'secondary' : 'destructive'} 
                           className={driver.status === 'Active' ? 'bg-green-500/20 text-green-700 hover:bg-green-500/30' : ''}>
                      {driver.status}
                    </Badge>
                  </TableCell>
                  <TableCell>{driver.since}</TableCell>
                  <TableCell>
                    <DropdownMenu>
                      <DropdownMenuTrigger asChild>
                        <Button aria-haspopup="true" size="icon" variant="ghost">
                          <MoreHorizontal className="h-4 w-4" />
                          <span className="sr-only">Toggle menu</span>
                        </Button>
                      </DropdownMenuTrigger>
                      <DropdownMenuContent align="end">
                        <DropdownMenuLabel>Actions</DropdownMenuLabel>
                        <DropdownMenuItem>Edit Profile</DropdownMenuItem>
                        <DropdownMenuItem>Assign Route</DropdownMenuItem>
                        <DropdownMenuItem className="text-destructive focus:bg-destructive/10 focus:text-destructive">Deactivate</DropdownMenuItem>
                      </DropdownMenuContent>
                    </DropdownMenu>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </div>
  );
}
